#!/usr/bin/env node
// scripts/build-bundle.js — produces jsanalyze/browser-bundle.js
//
// Concatenates every source file under src/ and consumers/ into
// a single IIFE that exposes `globalThis.Jsanalyze`. Each source
// file is wrapped in a per-module function so CommonJS `require`
// semantics (circular deps, lazy requires) survive intact.
//
// Usage:
//   node scripts/build-bundle.js
//
// The output is written to jsanalyze/browser-bundle.js. The
// bundle is self-contained except for:
//
//   * `globalThis.acorn`  — loaded separately via
//                           jsanalyze/vendor/acorn.js (a UMD
//                           build whose browser branch assigns
//                           to globalThis.acorn).
//
//   * `globalThis.__htmldomZ3Init` — registered by the Z3
//                           browser bootstrap
//                           (analyzer/jsanalyze-z3-browser.js
//                           or an equivalent) before the bundle
//                           runs its first analyse() call.
//
// Both dependencies are loaded by the host HTML page before
// the bundle so `require('./parse.js')` and `require('./z3.js')`
// find them via their environment probes.

'use strict';

const fs = require('fs');
const path = require('path');

const ROOT = path.resolve(__dirname, '..');
const SRC_DIR = path.join(ROOT, 'src');
const CONSUMERS_DIR = path.join(ROOT, 'consumers');
const OUT_FILE = path.join(ROOT, 'browser-bundle.js');

// Collect every .js file from src/ and consumers/. Path ids
// are relative-to-ROOT (so `src/domain.js`, `consumers/dom-convert.js`).
const modules = [];

function addDir(dir, prefix) {
  for (const f of fs.readdirSync(dir).sort()) {
    const full = path.join(dir, f);
    const st = fs.statSync(full);
    if (st.isDirectory()) continue;
    if (!f.endsWith('.js')) continue;
    modules.push({
      id: prefix + f,
      content: fs.readFileSync(full, 'utf8'),
    });
  }
}

addDir(SRC_DIR, 'src/');
addDir(CONSUMERS_DIR, 'consumers/');

// Loader wrapper. Uses a simple path-scoped require with
// relative resolution and a stub for Node builtins (which
// are unreachable in the browser via environment probes
// inside src/z3.js and src/parse.js). The stub returns
// a benign null so a late Node-branch taken by mistake in
// the browser surfaces as "Cannot read properties of null"
// instead of silently passing — the consumer knows to
// fail loudly.
const header = `// jsanalyze browser bundle — auto-generated by scripts/build-bundle.js.
// Do NOT edit by hand; run \`node jsanalyze/scripts/build-bundle.js\`
// to regenerate.
//
// Exposes \`globalThis.Jsanalyze\` = {
//   analyze, query, resetCache, AssumptionTracker,
//   consumers: { domConvert, cspDerive, fetchTrace },
// }.
//
// Environment contract:
//   * Must be loaded AFTER jsanalyze/vendor/acorn.js (sets
//     globalThis.acorn).
//   * If analyse() will ever walk branches that need Z3, load
//     analyzer/jsanalyze-z3-browser.js (or equivalent) before
//     the first analyse() call so globalThis.__htmldomZ3Init
//     is registered.
(function (global) {
  'use strict';
  if (typeof global === 'undefined') global = this;

  var __modules = Object.create(null);
  var __cache = Object.create(null);

  function __require(id) {
    if (__cache[id]) return __cache[id].exports;
    if (!__modules[id]) {
      throw new Error('jsanalyze browser bundle: module not found: ' + id);
    }
    var moduleObj = { exports: {} };
    __cache[id] = moduleObj;
    var req = __scopedRequire(id);
    __modules[id].call(moduleObj.exports, moduleObj, moduleObj.exports, req, id);
    return moduleObj.exports;
  }

  // Path-scoped require: relative ids are resolved against
  // the requiring module's directory. Non-relative ids
  // (Node builtins, npm packages) return null — code that
  // reaches them via a dead-branch probe will crash loudly.
  function __scopedRequire(fromId) {
    var lastSlash = fromId.lastIndexOf('/');
    var fromDir = lastSlash >= 0 ? fromId.slice(0, lastSlash + 1) : '';
    return function (id) {
      if (typeof id !== 'string') return null;
      if (id.charAt(0) !== '.') return null;
      return __require(__resolve(fromDir, id));
    };
  }

  function __resolve(dir, rel) {
    var parts = (dir + rel).split('/');
    var out = [];
    for (var i = 0; i < parts.length; i++) {
      var p = parts[i];
      if (p === '' || p === '.') continue;
      if (p === '..') { out.pop(); continue; }
      out.push(p);
    }
    return out.join('/');
  }
`;

const footer = `
  // --- Entry point: build the public API on __require('src/index.js')
  //     and assemble the consumer namespace so hosts can do
  //     \`Jsanalyze.consumers.domConvert.convertProject(files)\`.
  var api = __require('src/index.js');
  var consumers = {
    domConvert:  __require('consumers/dom-convert.js'),
    cspDerive:   __require('consumers/csp-derive.js'),
    fetchTrace:  __require('consumers/fetch-trace.js'),
    taintReport: __require('consumers/taint-report.js'),
    pocSynth:    __require('consumers/poc-synth.js'),
  };
  var out = {};
  for (var k in api) out[k] = api[k];
  out.consumers = consumers;
  global.Jsanalyze = out;
})(typeof globalThis !== 'undefined' ? globalThis :
   typeof window !== 'undefined' ? window :
   typeof self !== 'undefined' ? self : this);
`;

let body = header;
for (const m of modules) {
  body += '\n  __modules[' + JSON.stringify(m.id) + '] = function (module, exports, require, __id) {\n';
  body += m.content;
  body += '\n  };\n';
}
body += footer;

fs.writeFileSync(OUT_FILE, body, 'utf8');
const size = Buffer.byteLength(body, 'utf8');
console.log('wrote ' + OUT_FILE + ' (' + size + ' bytes, ' + modules.length + ' modules)');
